package hw04.model.paint.strategies;

import java.awt.Graphics;
import hw04.model.IBall;
import java.awt.Graphics2D;
import java.awt.Shape;
import java.awt.geom.AffineTransform;

/**
 * Shape painting strategy
 * @author charlielockyer
 *
 */
public class ShapePaintStrategy extends APaintStrategy {
	private Shape shape;

	/**
	 * Constructs a shape painting strategy
	 * @param shape the shape to paint
	 */
	public ShapePaintStrategy(Shape shape) {
		super(new AffineTransform());
		this.shape = at.createTransformedShape(shape);
	}

	/**
	 * Constructs a shape painting strategy given an affine transform as well
	 * @param at the affine transform
	 * @param shape the shape to paint
	 */
	public ShapePaintStrategy(AffineTransform at, Shape shape) {
		super(at);
		this.shape = shape;
	}

	@Override
	public void paintXfrm(Graphics g, IBall thisBall, AffineTransform at) {
		((Graphics2D) g).fill(at.createTransformedShape(shape));
	}

}

package hw04.model.paint.strategies;

import java.awt.Graphics;
import java.awt.geom.AffineTransform;

import hw04.model.IBall;

/**
 * A multi paint strategy that combines two paint strategies
 * @author charlielockyer
 *
 */
public class MultiPaintStrategy extends APaintStrategy {
	private APaintStrategy[] paintStrategies;
	/**
	 * Constructs a multi paint strategy
	 * @param paintStrategies the input paint strategies
	 */
	public MultiPaintStrategy(APaintStrategy... paintStrategies) {
		this(new AffineTransform(), paintStrategies);
	}

	/**
	 * Constructs a multi paint strategy given an affine as well
	 * @param at affine transform to use
	 * @param paintStrategies the input paint strategies
	 */
	public MultiPaintStrategy(AffineTransform at, APaintStrategy... paintStrategies) {
		super(at);
