package comp310.tests.hw04;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.awt.Color;
import java.awt.Graphics2D;
import java.awt.Point;
import java.awt.image.BufferedImage;
import java.util.concurrent.atomic.AtomicInteger;

import org.junit.jupiter.api.Test;

import hw04.model.Ball;
import hw04.model.IBall;
import hw04.model.IBallAlgo;
import hw04.model.IBallCmd;
import hw04.model.paint.strategies.APaintStrategy;
import hw04.model.paint.strategies.EllipsePaintStrategy;
import hw04.model.paint.strategies.MultiPaintStrategy;
import hw04.model.paint.strategies.SquarePaintStrategy;
import hw04.model.strategy.GravityStrategy;
import hw04.model.strategy.SwitcherStrategy;
import provided.utils.dispatcher.IDispatcher;
import provided.utils.dispatcher.impl.SequentialDispatcher;
import provided.utils.displayModel.IDimension;

class HW04AgentTest {

	private IDimension mockDim() {
		return new IDimension() {
			@Override
			public int getWidth() {
				return 200;
			}

			@Override
			public int getHeight() {
				return 200;
			}
		};
	}

	private IBallAlgo noOpAlgo() {
		return new IBallAlgo() {
			@Override
			public void caseDefault(IBall host) {
			}
		};
	}

	private Ball makeBall(Point location, Point velocity, int radius, Color color) {
		return new Ball(location, velocity, color, radius, mockDim(), null, noOpAlgo());
	}

	private Graphics2D graphicsFor(BufferedImage image) {
		Graphics2D g = image.createGraphics();
		g.setBackground(new Color(0, 0, 0, 0));
		g.clearRect(0, 0, image.getWidth(), image.getHeight());
		return g;
	}

	@Test
	void testSwitcherDelegatesToInstalledStrategy() {
		Ball ball = makeBall(new Point(30, 30), new Point(0, 0), 10, Color.RED);
		IDispatcher<IBallCmd> disp = new SequentialDispatcher<>();
		SwitcherStrategy switcher = new SwitcherStrategy();

		switcher.switchStrategy(new GravityStrategy());
		switcher.updateState(ball, disp);

		assertEquals(1, ball.getVelocity().y);
	}

	@Test
	void testEllipsePaintStrategyRendersAtBallCenter() {
		Ball ball = makeBall(new Point(60, 60), new Point(1, 0), 10, Color.RED);
		EllipsePaintStrategy strategy = new EllipsePaintStrategy();
		BufferedImage image = new BufferedImage(120, 120, BufferedImage.TYPE_INT_ARGB);
		Graphics2D g = graphicsFor(image);

		strategy.init(ball);
		strategy.paint(g, ball);

		assertEquals(Color.RED.getRGB(), image.getRGB(60, 60));
		assertTrue(image.getRGB(15, 15) != Color.RED.getRGB());
	}

	@Test
	void testSquarePaintStrategyPaintsCenteredSquare() {
		Ball ball = makeBall(new Point(40, 40), new Point(0, 1), 8, Color.BLUE);
		SquarePaintStrategy strategy = new SquarePaintStrategy();
		BufferedImage image = new BufferedImage(100, 100, BufferedImage.TYPE_INT_ARGB);
		Graphics2D g = graphicsFor(image);

		strategy.paint(g, ball);

		assertEquals(Color.BLUE.getRGB(), image.getRGB(40, 40));
		assertEquals(0, image.getRGB(10, 10));
	}

	@Test
	void testMultiPaintStrategyDelegatesToEachSubStrategy() {
		Ball ball = makeBall(new Point(50, 50), new Point(1, 0), 12, Color.GREEN);
		AtomicInteger initCount = new AtomicInteger();
		AtomicInteger cfgCount = new AtomicInteger();
		AtomicInteger xfrmCount = new AtomicInteger();

		class CountingPaintStrategy extends APaintStrategy {
			CountingPaintStrategy() {
				super(new java.awt.geom.AffineTransform());
			}

			@Override
			public void init(IBall host) {
				initCount.incrementAndGet();
			}

			@Override
			protected void paintCfg(java.awt.Graphics g, IBall host) {
				cfgCount.incrementAndGet();
			}

			@Override
			public void paintXfrm(java.awt.Graphics g, IBall host, java.awt.geom.AffineTransform at) {
				xfrmCount.incrementAndGet();
			}
		}

		MultiPaintStrategy strategy = new MultiPaintStrategy(new CountingPaintStrategy(), new CountingPaintStrategy());

		strategy.init(ball);
		strategy.paint(graphicsFor(new BufferedImage(100, 100, BufferedImage.TYPE_INT_ARGB)), ball);

		assertEquals(2, initCount.get());
		assertEquals(2, cfgCount.get());
		assertEquals(2, xfrmCount.get());
	}
}

